import React from 'react';
import { Routes, Route } from 'react-router-dom';
import StudentLanding from './components/StudentLanding';
import ProfessorLanding from './pages/ProfessorLanding';
import AdminLanding from './pages/AdminLanding';
import SecretaryLanding from './pages/SecretaryLanding';
// Import other necessary components

const App = () => {
  return (
    <Routes>
      <Route path="/" element={<StudentLanding />} />
      <Route path="/professor" element={<ProfessorLanding />} />
      <Route path="/admin" element={<AdminLanding />} />
      <Route path="/secretary" element={<SecretaryLanding />} />
      {/* Add other routes as needed */}
    </Routes>
  );
};

export default App;
